+/// Generate a Zig stub module that loads a C extension (.so) via dlopen
+/// This is used when a .so file is found without a corresponding .py source
+/// The generated code:
+/// 1. Loads the .so at runtime using std.DynLib
+/// 2. Looks up PyInit_<modulename> function
+/// 3. Calls it to initialize the module and get PyObject*
+/// 4. Wraps functions for Zig access
+pub fn generateCExtensionStub(
+    allocator: std.mem.Allocator,
+    module_name: []const u8,
+    so_path: []const u8,
+) ![]const u8 {
+    // Extract the short name (after last dot) for PyInit_ function
+    const short_name = blk: {
+        if (std.mem.lastIndexOf(u8, module_name, ".")) |idx| {
+            break :blk module_name[idx + 1 ..];
+        }
+        break :blk module_name;
+    };
+
+    // Generate identifier-safe name (replace dots with underscores)
+    var zig_name_buf: [256]u8 = undefined;
+    var zig_name_len: usize = 0;
+    for (module_name) |c| {
+        if (zig_name_len >= zig_name_buf.len) break;
+        zig_name_buf[zig_name_len] = if (c == '.') '_' else c;
+        zig_name_len += 1;
+    }
+    const zig_name = zig_name_buf[0..zig_name_len];
+
+    // Generate C extension wrapper module
+    // This module:
+    // - Loads the .so at first access
+    // - Calls PyInit_<name> to get module PyObject*
+    // - Provides stub functions that delegate to C extension via c_interop
+    return try std.fmt.allocPrint(allocator,
+        \\/// C extension module: {s}
+        \\/// Loaded from: {s}
+        \\/// Generated by metal0 - DO NOT EDIT
+        \\const std = @import("std");
+        \\const runtime = @import("runtime");
+        \\const c_interop = @import("c_interop");
+        \\
+        \\/// C extension module handle
+        \\var _lib_handle: ?std.DynLib = null;
+        \\var _module_obj: ?*c_interop.PyObject = null;
+        \\
+        \\/// Load the C extension module
+        \\fn ensureLoaded() !*c_interop.PyObject {{
+        \\    if (_module_obj) |m| return m;
+        \\
+        \\    // Load shared library
+        \\    _lib_handle = std.DynLib.open("{s}") catch |err| {{
+        \\        std.debug.print("Failed to load C extension '{s}': {{}}\n", .{{err}});
+        \\        return error.CExtensionLoadFailed;
+        \\    }};
+        \\
+        \\    // Look up PyInit_<module> function
+        \\    const init_fn = _lib_handle.?.lookup(
+        \\        *const fn () callconv(.C) ?*c_interop.PyObject,
+        \\        "PyInit_{s}"
+        \\    ) orelse {{
+        \\        std.debug.print("C extension '{s}' missing PyInit_{s}\n", .{{}});
+        \\        return error.CExtensionInitNotFound;
+        \\    }};
+        \\
+        \\    // Call init function to get module
+        \\    _module_obj = init_fn() orelse {{
+        \\        std.debug.print("PyInit_{s} returned null\n", .{{}});
+        \\        return error.CExtensionInitFailed;
+        \\    }};
+        \\
+        \\    return _module_obj.?;
+        \\}}
+        \\
+        \\/// Module struct for attribute access
+        \\pub const {s} = struct {{
+        \\    /// Get attribute from C extension module
+        \\    pub fn getattr(name: []const u8) !*c_interop.PyObject {{
+        \\        const mod = try ensureLoaded();
+        \\        return c_interop.PyObject_GetAttrString(mod, name.ptr) orelse
+        \\            return error.AttributeError;
+        \\    }}
+        \\
+        \\    /// Call a function in the C extension
+        \\    pub fn call(name: []const u8, args: anytype) !*c_interop.PyObject {{
+        \\        const func = try getattr(name);
+        \\        return c_interop.PyObject_Call(func, args, null) orelse
+        \\            return error.CallFailed;
+        \\    }}
+        \\}};
+        \\
+    , .{
+        module_name,
+        so_path,
+        so_path,
+        module_name,
+        short_name,
+        module_name,
+        short_name,
+        short_name,
+        zig_name,
+    });
+}
